import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"A Survey on the Security of Long-Term Memory in LLM Agents: Toward Mnemonic Sovereignty","description":"","frontmatter":{"title":"A Survey on the Security of Long-Term Memory in LLM Agents: Toward Mnemonic Sovereignty","arxiv_id":2604.16548,"authors":"Zehao Lin, Chunyu Li, Kai Chen","published":"2026-04-17T00:00:00.000Z","source":"https://arxiv.org/abs/2604.16548","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-04-17-security-long-term-memory-mnemonic-sovereignty-2604-16548.md","filePath":"research/papers/2026-04-17-security-long-term-memory-mnemonic-sovereignty-2604-16548.md","lastUpdated":1779901665000}'),n={name:"research/papers/2026-04-17-security-long-term-memory-mnemonic-sovereignty-2604-16548.md"};function i(s,e,l,d,h,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="a-survey-on-the-security-of-long-term-memory-in-llm-agents-toward-mnemonic-sovereignty" tabindex="-1">A Survey on the Security of Long-Term Memory in LLM Agents: Toward Mnemonic Sovereignty <a class="header-anchor" href="#a-survey-on-the-security-of-long-term-memory-in-llm-agents-toward-mnemonic-sovereignty" aria-label="Permalink to &quot;A Survey on the Security of Long-Term Memory in LLM Agents: Toward Mnemonic Sovereignty&quot;">​</a></h1><p><strong>ArXiv</strong>: 2604.16548 | <strong>Date</strong>: 2026-04-17 | <strong>Authors</strong>: Zehao Lin, Chunyu Li, Kai Chen | <strong>Category</strong>: cs.CR, cs.AI</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>首篇針對 LLM agent 長期記憶安全性的系統性綜述。安全研究重心正從靜態訓練資料洩漏轉向動態威脅：「擁有持續長期記憶的系統是否可以跨 session 被持續塑造、投毒、未授權存取，以及跨共享組織狀態傳播？」63 頁，7 圖，10 表。</p><h2 id="核心框架-記憶生命週期安全" tabindex="-1">核心框架：記憶生命週期安全 <a class="header-anchor" href="#核心框架-記憶生命週期安全" aria-label="Permalink to &quot;核心框架：記憶生命週期安全&quot;">​</a></h2><p>六個操作階段 × 四個安全目標的矩陣：</p><p><strong>操作階段</strong>：Write → Store → Retrieve → Execute → Share → Forget/Rollback</p><p><strong>安全目標</strong>：完整性（Integrity）、機密性（Confidentiality）、可用性（Availability）、治理（Governance）</p><h2 id="主要發現" tabindex="-1">主要發現 <a class="header-anchor" href="#主要發現" aria-label="Permalink to &quot;主要發現&quot;">​</a></h2><h3 id="文獻分佈失衡" tabindex="-1">文獻分佈失衡 <a class="header-anchor" href="#文獻分佈失衡" aria-label="Permalink to &quot;文獻分佈失衡&quot;">​</a></h3><p>現有研究高度集中在 Write 和 Retrieve 時的完整性攻擊，以下領域「研究稀少」：</p><ul><li>機密性威脅</li><li>可用性攻擊</li><li>Storage/Forgetting 機制</li><li>良性持久性失敗</li></ul><h3 id="治理空白" tabindex="-1">治理空白 <a class="header-anchor" href="#治理空白" aria-label="Permalink to &quot;治理空白&quot;">​</a></h3><p>目前無任何已發表的架構完整實作論文所識別的<strong>9 個治理原語</strong>。</p><h3 id="llm-作為記憶安全工具" tabindex="-1">LLM 作為記憶安全工具 <a class="header-anchor" href="#llm-作為記憶安全工具" aria-label="Permalink to &quot;LLM 作為記憶安全工具&quot;">​</a></h3><p>使用 LLM 本身來強化記憶安全「仍然稀少但至關重要」。</p><h2 id="核心概念-mnemonic-sovereignty-記憶主權" tabindex="-1">核心概念：Mnemonic Sovereignty（記憶主權） <a class="header-anchor" href="#核心概念-mnemonic-sovereignty-記憶主權" aria-label="Permalink to &quot;核心概念：Mnemonic Sovereignty（記憶主權）&quot;">​</a></h2><p>定義：「對寫入內容、讀取者、更新授權時機、可遺忘狀態的<strong>可驗證、可恢復的治理</strong>。」</p><p>將記憶治理品質定位為未來安全 agent 系統的核心差異化指標，與傳統的召回容量並列。</p><h2 id="攻擊向量分類" tabindex="-1">攻擊向量分類 <a class="header-anchor" href="#攻擊向量分類" aria-label="Permalink to &quot;攻擊向量分類&quot;">​</a></h2><table tabindex="0"><thead><tr><th>攻擊類型</th><th>描述</th></tr></thead><tbody><tr><td>記憶投毒（Memory Poisoning）</td><td>惡意寫入影響後續行為</td></tr><tr><td>記憶提取（Extraction）</td><td>未授權讀取私密資訊</td></tr><tr><td>檢索腐化（Retrieval Corruption）</td><td>操縱 RAG 查詢結果</td></tr><tr><td>控制流劫持（Control-flow Hijacking）</td><td>通過記憶影響 agent 行為路徑</td></tr><tr><td>跨 agent 傳播（Cross-agent Propagation）</td><td>共享記憶庫中的病毒式擴散</td></tr><tr><td>回滾機制（Rollback）</td><td>防止或強制記憶狀態恢復</td></tr></tbody></table><h2 id="對-workspace-的意義" tabindex="-1">對 Workspace 的意義 <a class="header-anchor" href="#對-workspace-的意義" aria-label="Permalink to &quot;對 Workspace 的意義&quot;">​</a></h2><p>與 <code>2026-05-13-useful-memories-faulty-llm</code> 形成互補：</p><ul><li>前者研究<strong>認知失真</strong>（整合引入的準確率損失）</li><li>本文研究<strong>安全威脅</strong>（惡意行為者對記憶系統的攻擊）</li></ul><p>生產環境記憶系統需要同時防範：認知退化（整合失真）+ 安全威脅（惡意投毒）。</p><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Memory Architecture / Safety &amp; Alignment</strong> — 記憶安全的第一篇系統性綜述，Mnemonic Sovereignty 框架為評估 agent 記憶系統的安全成熟度提供標準。</p>',27)])])}const u=t(n,[["render",i]]);export{g as __pageData,u as default};
